1: import React, { useState, useEffect } from 'react';
2: import { Search, AlertCircle, Calendar, StickyNote, Flag, Clock, CheckCircle2 } from 'lucide-react';
3: import { useLanguage } from '../utils/LanguageContext';
4: import { db, ref, onValue, set } from '../utils/firebase';
5: import { saveEngineeringCheck } from '../utils/engineeringCheck';
6: import './PipelineView.css';
7: 
8: export default function PipelineView({ data, currentUser, userProfile }) {
9:   const { t, language } = useLanguage();
10:   if (!data) return null;
11: 
12:   const [filter, setFilter] = useState('ALL');
13:   const [searchTerm, setSearchTerm] = useState('');
14:   const [projectNotes, setProjectNotes] = useState({});
15:   const [engineeringChecks, setEngineeringChecks] = useState({});
16: 
17:   // Listen for project notes and engineering checks from Firebase in real-time
18:   useEffect(() => {
19:     if (!db) return;
20:     const notesRef = ref(db, 'project_notes');
21:     const unsubscribeNotes = onValue(notesRef, (snapshot) => {
22:       setProjectNotes(snapshot.val() || {});
23:     });
24: 
25:     const engChecksRef = ref(db, 'engineering_checks');
26:     const unsubscribeEngChecks = onValue(engChecksRef, (snapshot) => {
27:       setEngineeringChecks(snapshot.val() || {});
28:     });
29: 
30:     return () => {
31:       unsubscribeNotes();
32:       unsubscribeEngChecks();
33:     };
34:   }, []);
35: 
36:   const handleEngineeringStart = async (so) => {
37:     const currentCheck = engineeringChecks[so] || {};
38:     const userName = userProfile?.designerName || currentUser?.email || 'Unknown User';
39:     const updatedCheck = { 
40:       ...currentCheck, 
41:       started: new Date().toISOString(),
42:       user: userName
43:     };
44:     setEngineeringChecks(prev => ({ ...prev, [so]: updatedCheck }));
45:     await saveEngineeringCheck(so, updatedCheck);
46:   };
47: 
48:   const handleEngineeringFinish = async (so) => {
49:     const currentCheck = engineeringChecks[so] || {};
50:     const userName = userProfile?.designerName || currentUser?.email || 'Unknown User';
51:     const updatedCheck = { 
52:       ...currentCheck, 
53:       finished: new Date().toISOString(),
54:       user: userName
55:     };
56:     setEngineeringChecks(prev => ({ ...prev, [so]: updatedCheck }));
57:     await saveEngineeringCheck(so, updatedCheck);
58:   };
59: 
60:   const { priorityAnalysis, onHoldNotes } = data;
61: 
62:   // Combine data or just use priorityAnalysis as the main source
63:   const projects = priorityAnalysis.filter(p => {
64:     const matchesFilter = filter === 'ALL' || p.status.toUpperCase() === filter.toUpperCase();
65:     const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
66:                           p.so.includes(searchTerm) ||
67:                           p.eng.toLowerCase().includes(searchTerm.toLowerCase());
68:     return matchesFilter && matchesSearch;
69:   });
70: 
71:   const getStatusColor = (status) => {
72:     const s = status.toUpperCase();
73:     if (s.includes('HOLD')) return 'status-hold';
74:     if (s.includes('CHECK')) return 'status-check';
75:     if (s.includes('REVIEW')) return 'status-review';
76:     if (s.includes('ENG')) return 'status-eng';
77:     return 'status-default';
78:   };
79: 
80:   const getStatusLabel = (status) => {
81:     if (!status) return '';
82:     const s = status.toUpperCase();
83:     if (s.includes('HOLD')) return language === 'es' ? 'EN PAUSA' : 'ON HOLD';
84:     if (s.includes('CHECK')) return 'Check';
85:     if (s.includes('REVIEW')) return language === 'es' ? 'Revisión' : 'Review';
86:     if (s.includes('ENG')) return language === 'es' ? 'Ingeniería' : 'Engineering';
87:     if (s.includes('NEST')) return 'Nesting';
88:     return status;
89:   };
90: 
91:   const getFilterLabel = (filterVal) => {
92:     if (language === 'es') {
93:       switch (filterVal) {
94:         case 'ALL': return 'TODOS';
95:         case 'ON HOLD': return 'EN PAUSA';
96:         case 'CHECK': return 'CHECK';
97:         case 'REVIEW': return 'REVISIÓN';
98:         case 'ENGINEERING': return 'INGENIERÍA';
99:         default: return filterVal;
100:       }
101:     }
102:     return filterVal;
103:   };
104: 
105:   const getOnHoldNote = (projectName) => {
106:     // try to match part of the name
107:     const note = onHoldNotes.find(n => projectName.includes(n.project) || n.project.includes(projectName));
108:     return note ? note.notes : null;
109:   };
110: 
111:   return (
112:     <div className="pipeline-view animate-fade-in">
113:       <header className="view-header">
114:         <h1 className="page-title">{t('pipeline.title')}</h1>
115:         <div className="controls">
116:           <div className="search-bar glass-card">
117:             <Search size={18} className="text-muted" />
118:             <input 
119:               type="text" 
120:               placeholder={t('pipeline.searchPlaceholder')}
121:               value={searchTerm}
122:               onChange={(e) => setSearchTerm(e.target.value)}
123:             />
124:           </div>
125:           <div className="filter-chips">
126:             {['ALL', 'ON HOLD', 'CHECK', 'REVIEW', 'ENGINEERING'].map(f => (
127:               <button 
128:                 key={f} 
129:                 className={`chip ${filter === f ? 'active' : ''}`}
130:                 onClick={() => setFilter(f)}
131:               >
132:                 {getFilterLabel(f)}
133:               </button>
134:             ))}
135:           </div>
136:         </div>
137:       </header>
138: 
139:       <div className="project-list">
140:         {projects.length === 0 ? (
141:           <div className="no-results text-muted">{t('pipeline.noProjects')}</div>
142:         ) : (
143:           projects.map((project, idx) => {
144:             const onHoldNote = project.status.toUpperCase() === 'ON HOLD' 
145:               ? (project.onHoldReason || getOnHoldNote(project.name)) 
146:               : null;
147:             
148:             return (
149:               <div key={idx} className="project-card glass-card">
150:                 <div className="project-main">
151:                   <div className="project-id">#{project.so}</div>
152:                   <h3 className="project-name">{project.name}</h3>
153:                   <div className="project-meta">
154:                     <span className="meta-item">
155:                       <Calendar size={14} />
156:                       {project.install}
157:                     </span>
158:                     <span className="meta-item eng-badge">
159:                       ENG: {project.eng}
160:                     </span>
161:                   </div>
162:                 </div>
163:                 
164:                 <div className="project-side">
165:                   <span className={`status-badge ${getStatusColor(project.status)}`}>
166:                     {getStatusLabel(project.status)}
167:                   </span>
168:                 </div>
169: 
170:                 {onHoldNote && (
171:                   <div className="on-hold-alert">
172:                     <AlertCircle size={16} />
173:                     <p>{onHoldNote}</p>
174:                   </div>
175:                 )}
176: 
177:                 {/* Engineering Check Controls */}
178:                 <div className="pipeline-eng-check-controls">
179:                   <div className="pipeline-eng-check-header">
180:                     <span className="pipeline-eng-check-title">{t('myProjects.engineeringCheck', 'Engineering Time')}</span>
181:                   </div>
182:                   <div className="pipeline-eng-check-buttons">
183:                     <button 
184:                       onClick={() => handleEngineeringStart(project.so)}
185:                       className={`btn-sm ${engineeringChecks[project.so]?.started ? 'btn-secondary active-check' : 'btn-primary'}`}
186:                     >
187:                       <Clock size={14} />
188:                       {engineeringChecks[project.so]?.started ? new Date(engineeringChecks[project.so].started).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : 'Start'}
189:                     </button>
190:                     <button 
191:                       onClick={() => handleEngineeringFinish(project.so)}
192:                       className={`btn-sm ${engineeringChecks[project.so]?.finished ? 'btn-secondary active-check' : 'btn-secondary'}`}
193:                       disabled={!engineeringChecks[project.so]?.started}
194:                     >
195:                       <CheckCircle2 size={14} />
196:                       {engineeringChecks[project.so]?.finished ? new Date(engineeringChecks[project.so].finished).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) : 'Finish'}
197:                     </button>
198:                     {engineeringChecks[project.so]?.user && (
199:                       <span className="eng-check-user">
200:                         ({engineeringChecks[project.so].user})
201:                       </span>
202:                     )}
203:                   </div>
204:                 </div>
205: 
206:                 {/* Project Notes (from My Projects) */}
207:                 {(projectNotes[project.so] || []).length > 0 && (
208:                   <div className="pipeline-notes-section">
209:                     <div className="pipeline-notes-header">
210:                       <StickyNote size={13} />
211:                       <span>{language === 'es' ? 'Notas' : 'Notes'} ({(projectNotes[project.so] || []).length})</span>
212:                     </div>
213:                     <div className="pipeline-notes-list">
214:                       {(projectNotes[project.so] || []).map(note => (
215:                         <div key={note.id} className={`pipeline-note-item ${note.priority ? 'priority' : 'normal'}`}>
216:                           <div className="pipeline-note-top">
217:                             <span className={`pipeline-note-tag ${note.priority ? 'priority' : 'normal'}`}>
218:                               {note.priority
219:                                 ? (language === 'es' ? '⚑ Prioritaria' : '⚑ Priority')
220:                                 : (language === 'es' ? 'Normal' : 'Normal')}
221:                             </span>
222:                             <span className="pipeline-note-date">
223:                               {new Date(note.createdAt).toLocaleDateString(language === 'es' ? 'es-AR' : 'en-US', {
224:                                 day: 'numeric', month: 'short'
225:                               })}
226:                             </span>
227:                           </div>
228:                           <p className="pipeline-note-text">{note.text}</p>
229:                         </div>
230:                       ))}
231:                     </div>
232:                   </div>
233:                 )}
234:               </div>
235:             );
236:           })
237:         )}
238:       </div>
239:     </div>
240:   );
241: }
